parameters.jsCode:
const bookings = $input.first().json.bookings || [];
const now = new Date();
const ist = new Date(now.getTime() + (5.5 * 60 * 60 * 1000));

const todayStr = String(ist.getDate()).padStart(2,'0') + '-' + String(ist.getMonth()+1).padStart(2,'0') + '-' + ist.getFullYear();
const currentHour = ist.getHours();
const targetHour = currentHour + 1;

function parseHour(timeStr) {
  const t = String(timeStr || '').toLowerCase().trim();
  const ampm = t.match(/^(\d{1,2})(am|pm)$/);
  if (ampm) {
    let h = parseInt(ampm[1]);
    if (ampm[2] === 'pm' && h !== 12) h += 12;
    if (ampm[2] === 'am' && h === 12) h = 0;
    return h;
  }
  const h24 = t.match(/^(\d{1,2}):(\d{2})$/);
  if (h24) return parseInt(h24[1]);
  return null;
}

function formatTime(timeStr) {
  const t = String(timeStr || '').toLowerCase().trim();
  const match24 = t.match(/^(\d{1,2}):(\d{2})$/);
  if (match24) {
    const h = parseInt(match24[1]);
    if (h === 0) return '12am';
    if (h < 12) return h + 'am';
    if (h === 12) return '12pm';
    return (h - 12) + 'pm';
  }
  return timeStr;
}

const filtered = bookings.filter(b => {
  if (b.date !== todayStr) return false;
  if (b.status === 'Cancelled') return false;
  const bookingHour = parseHour(b.time);
  return bookingHour === targetHour;
});

return filtered.map(b => ({ json: { ...b, timeFormatted: formatTime(b.time) } }));

